parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "case_id": {
      "type": "string",
      "description": "The unique identifier of the case, copied directly from the input data."
    },
    "ip_address": {
      "type": "string",
      "description": "The source IP address extracted from the 'source' field and verified in the logs."
    },
    "is_actual_threat": {
      "type": "boolean",
      "description": "Your professional judgment: true if this is an actual, successful, or highly probable attack; false if it is a false positive, benign activity, or minor attempt."
    },
    "dugaan_kejadian": {
      "type": "string",
      "description": "Short description of the suspected incident type, e.g. 'Brute Force SSH', 'SQL Injection', 'Lateral Movement'. Max 10 words, written in English."
    },
    "ringkasan_log": {
      "type": "string",
      "description": "Narrative summary in English of the chronology and identified attack pattern from the logs."
    },
    "alasan_ai_agent": {
      "type": "string",
      "description": "Logical, evidence-based explanation in English of why this conclusion was reached, referencing specific log details."
    },
    "respon_lanjutan": {
      "type": "string",
      "description": "Specific, actionable recommendation in English, mentioning the relevant IP/host/user."
    },
    "mitre_mapping": {
      "type": "array",
      "items": { "type": "string" },
      "description": "List of relevant MITRE ATT&CK tactics/techniques in format 'TXXXX.XXX - Technique Name'. Empty array [] if none clearly apply."
    },
    "urgensi": {
      "type": "string",
      "enum": ["low", "medium", "high", "critical"],
      "description": "Urgency level based on potential impact and attack stage."
    },
    "confidence_factor": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Confidence level of the diagnosis, 0.0 to 1.0."
    }
  },
  "required": [
    "case_id",
    "ip_address",
    "is_actual_threat",
    "dugaan_kejadian",
    "ringkasan_log",
    "alasan_ai_agent",
    "respon_lanjutan",
    "mitre_mapping",
    "urgensi",
    "confidence_factor"
  ]
}

parameters.jsCode:
// Ambil waktu dari Code1
const currentWindow = $('Code1').item.json;
const staticData = $getWorkflowStaticData('global');

if (staticData.emptyCounter === undefined) {
  staticData.emptyCounter = 0;
}

let nextGte = currentWindow.gte;
let nextLt = currentWindow.lt;

staticData.emptyCounter += 1;

// Jika sudah 3x putaran kosong (2 periode toleransi habis)
if (staticData.emptyCounter >= 3) {
  staticData.emptyCounter = 0; // Reset counter

  // PAKSA LONCAT KE JAM BERIKUTNYA
  nextGte = currentWindow.lt;
  const nextHour = new Date(currentWindow.lt);
  nextHour.setUTCHours(nextHour.getUTCHours() + 1);
  nextLt = nextHour.toISOString();
} else {
  // TAHAN DI JAM YANG SAMA
  nextGte = currentWindow.gte;
  nextLt = currentWindow.lt;
}

// Kirimkan hasilnya langsung lewat JSON ke node berikutnya (Wait -> Code1)
return [{ 
  json: { 
    status: "jalur_false_kosong_terproses", 
    menitTunggu: 10,
    operGte: nextGte,
    operLt: nextLt
  } 
}];

const currentWindow = $('Code1').item.json;
const staticData = $getWorkflowStaticData('global');

// Bersihkan counter karena ada data sukses
staticData.emptyCounter = 0;

// LANGSUNG MAJU 1 JAM PENUH
const nextGte = currentWindow.lt;
const nextHour = new Date(currentWindow.lt);
nextHour.setUTCHours(nextHour.getUTCHours() + 1);
const nextLt = nextHour.toISOString();

return [{ 
  json: { 
    status: "jalur_true_sukses_maju_satu_jam", 
    menitTunggu: 5,
    operGte: nextGte,
    operLt: nextLt
  } 
}];

// Waktu fallback awal saat pertama kali workflow di-klik Start
let gteTime = '2026-07-01T16:00:00Z';
let ltTime = '2026-07-01T17:00:00Z';

try {
  // Ambil data kiriman terakhir yang lolos lewat node Wait
  const lastWaitOutput = $('Wait').item.json;

  if (lastWaitOutput && lastWaitOutput.operGte && lastWaitOutput.operLt) {
    // Jika ada waktu hasil operan dari update / update1, gunakan ini!
    gteTime = lastWaitOutput.operGte;
    ltTime = lastWaitOutput.operLt;
  }
} catch (e) {
  // Jika run pertama kali dan node Wait belum punya data, dia aman pakai fallback di atas
}

return [{ 
  json: { 
    gte: gteTime, 
    lt: ltTime 
  } 
}];
